import os
import json
import time
import hashlib
import threading
from datetime import datetime, timedelta
from typing import Any, Dict, Optional
from flask import Flask, request, jsonify

class SecureCache:
    def __init__(self, cache_dir: str = "cache", ttl: int = 3600):
        self.cache_dir = cache_dir
        self.ttl = ttl
        self.lock = threading.Lock()
        
        if not os.path.exists(cache_dir):
            os.makedirs(cache_dir)
    
    def _get_cache_key(self, url: str, params: Dict[str, Any]) -> str:
        """Generate secure cache key from URL and parameters"""
        cache_string = f"{url}_{json.dumps(params, sort_keys=True, separators=(',', ':'))}"
        return hashlib.sha256(cache_string.encode()).hexdigest()
    
    def _is_expired(self, timestamp: float) -> bool:
        """Check if cache entry is expired"""
        return time.time() > timestamp + self.ttl
    
    def _validate_data(self, data: Any) -> bool:
        """Validate that data is safe to cache"""
        try:
            json.dumps(data)
            return True
        except (TypeError, ValueError):
            return False
    
    def get(self, url: str, params: Dict[str, Any]) -> Optional[Any]:
        """Retrieve cached data"""
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'r', encoding='utf-8') as f:
                cache_data = json.load(f)
            
            if self._is_expired(cache_data['timestamp']):
                os.remove(cache_file)
                return None
            
            return cache_data['data']
        except (json.JSONDecodeError, KeyError, OSError):
            return None
    
    def set(self, url: str, params: Dict[str, Any], data: Any) -> bool:
        """Store data in cache"""
        if not self._validate_data(data):
            return False
        
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        try:
            with self.lock:
                cache_data = {
                    'timestamp': time.time(),
                    'data': data
                }
                with open(cache_file, 'w', encoding='utf-8') as f:
                    json.dump(cache_data, f, ensure_ascii=False, separators=(',', ':'))
            return True
        except (OSError, TypeError):
            return False

app = Flask(__name__)
